<?php /** Fuel lookup endpoint. */ declare(strict_types=1);require_once __DIR__.'/../config/config.php';requireAuth();enforceModuleAccess('fuel');$q='%'.trim((string)($_GET['q']??'')).'%';$s=getDb()->prepare('SELECT f.id,v.registration_number,f.cost,f.logged_date FROM fuel_logs f JOIN vehicles v ON v.id=f.vehicle_id WHERE v.registration_number LIKE ? LIMIT 20');$s->execute([$q]);jsonResponse(['ok'=>true,'rows'=>$s->fetchAll()]);
